/*
  # Seed Community sidebar groups and pages

  Creates 7 sidebar groups with ~30 child topic pages for the
  Community section. Organized from understanding to action to
  participation: what CivikStack reveals, community services,
  using evidence, contributing, practitioners, research, and mission.
*/

DO $$
DECLARE
  v_section_id uuid;
  v_group_id uuid;
BEGIN
  SELECT id INTO v_section_id FROM nav_sections WHERE slug = 'community';

  -- Group 1: What CivikStack Reveals
  VALUES (v_section_id, 'What CivikStack Reveals', 'what-civikstack-reveals', 1)
  RETURNING id INTO v_group_id;


  -- Group 2: Your Community's Services
  VALUES (v_section_id, 'Your Community''s Services', 'your-communitys-services', 2)
  RETURNING id INTO v_group_id;


  -- Group 3: Using the Evidence
  VALUES (v_section_id, 'Using the Evidence', 'using-the-evidence', 3)
  RETURNING id INTO v_group_id;


  -- Group 4: Contributing to the Ecosystem
  VALUES (v_section_id, 'Contributing to the Ecosystem', 'contributing-to-the-ecosystem', 4)
  RETURNING id INTO v_group_id;


  -- Group 5: For Practitioners in the Community
  VALUES (v_section_id, 'For Practitioners in the Community', 'for-practitioners-in-the-community', 5)
  RETURNING id INTO v_group_id;


  -- Group 6: Research and Journalism
  VALUES (v_section_id, 'Research and Journalism', 'research-and-journalism', 6)
  RETURNING id INTO v_group_id;


  -- Group 7: The Foundation's Mission
  VALUES (v_section_id, 'The Foundation''s Mission', 'the-foundations-mission', 7)
  RETURNING id INTO v_group_id;


END $$;
